-- ========== CLAN TAG ==========
local CLAN_GRADIENT_NAME = "__TTH_ClanGradient"
local textLocks = setmetatable({}, { __mode = "k" })
local function lockText(label, desired)
    if not label or typeof(label) ~= "Instance" then return end
    if not (label:IsA("TextLabel") or label:IsA("TextBox")) then return end
    local rec = textLocks[label]
    if rec then
        rec.desired = desired
        if label.Text ~= desired then rec.applying = true; label.Text = desired; rec.applying = false end
        return
    end
    rec = { desired = desired, applying = false }
    textLocks[label] = rec
    rec.textConn = label:GetPropertyChangedSignal("Text"):Connect(function()
        if rec.applying then return end
        if label.Text ~= rec.desired then
            rec.applying = true; pcall(function() label.Text = rec.desired end); rec.applying = false
        end
    end)
    rec.ancConn = label.AncestryChanged:Connect(function(_, parent)
        if not parent then
            if rec.textConn then rec.textConn:Disconnect() end
            if rec.ancConn then rec.ancConn:Disconnect() end
            textLocks[label] = nil
        end
    end)
    rec.applying = true; pcall(function() label.Text = desired end); rec.applying = false
end
local function unlockText(label)
    local rec = textLocks[label]; if not rec then return end
    if rec.textConn then rec.textConn:Disconnect() end
    if rec.ancConn then rec.ancConn:Disconnect() end
    textLocks[label] = nil
end
local function styleClanLabel(label)
    if not label then return end
    label.Font = Enum.Font.FredokaOne
    label.TextStrokeTransparency = 0.1
    label.TextStrokeColor3 = Config.Clan.StrokeColor
    label.TextColor3 = Config.Clan.TextColor
    local old = label:FindFirstChild(CLAN_GRADIENT_NAME); if old then old:Destroy() end
    if not Config.Clan.GradientEnabled then return end
    local g = Instance.new("UIGradient")
    g.Name = CLAN_GRADIENT_NAME
    g.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0, Config.Clan.GradientA),
        ColorSequenceKeypoint.new(0.5, Config.Clan.GradientB),
        ColorSequenceKeypoint.new(1, Config.Clan.GradientC),
    })
    g.Parent = label
end
local function applyClan()
    local pg = LocalPlayer:FindFirstChildOfClass("PlayerGui"); if not pg then return end
    local tag = pg:FindFirstChild("LocalResellerNameTag"); if not tag then return end
    local main = tag:FindFirstChild("MainContainer"); if not main then return end
    local clanLbl = main:FindFirstChild("ClanText") or main:FindFirstChild("Clantext")
    if not clanLbl then return end
    if Config.Clan.Enabled then
        lockText(clanLbl, Config.Clan.Text); styleClanLabel(clanLbl)
    else
        unlockText(clanLbl)
        local g = clanLbl:FindFirstChild(CLAN_GRADIENT_NAME); if g then g:Destroy() end
    end
end
task.spawn(function() while true do task.wait(0.5); if Config.Clan.Enabled then applyClan() end end end)

