local function AddItemToCache(obj)
    if not obj then return end
    local droppedFolder = Workspace:FindFirstChild("DroppedItems")
    local isInDropped, inShopZone, shopZone = false, false, nil
    local ancestor = obj
    while ancestor and ancestor ~= Workspace and ancestor ~= game do
        if ancestor:IsA("Model") and Players:GetPlayerFromCharacter(ancestor) then return end
        if droppedFolder and ancestor == droppedFolder then isInDropped = true end
        if string.find(ancestor.Name, "Shop_ShopZone") == 1 then inShopZone = true; shopZone = ancestor end
        ancestor = ancestor.Parent
    end
    if not isInDropped and not inShopZone then return end
    local detectedItem, possibleIds = nil, {}
    local function addId(instance)
        if instance:IsA("MeshPart") or instance:IsA("SpecialMesh") then
            if instance.MeshId ~= "" then table.insert(possibleIds, instance.MeshId:lower()) end
        elseif instance:IsA("Shirt") then
            if instance.ShirtTemplate ~= "" then table.insert(possibleIds, instance.ShirtTemplate:lower()) end
        elseif instance:IsA("Pants") then
            if instance.PantsTemplate ~= "" then table.insert(possibleIds, instance.PantsTemplate:lower()) end
        elseif instance:IsA("ShirtGraphic") then
            if instance.Graphic ~= "" then table.insert(possibleIds, instance.Graphic:lower()) end
        elseif instance:IsA("Decal") then
            if instance.Texture ~= "" then table.insert(possibleIds, instance.Texture:lower()) end
        end
    end
    if obj:IsA("Model") then for _, c in ipairs(obj:GetDescendants()) do addId(c) end else addId(obj) end
    for _, rawId in ipairs(possibleIds) do
        local mId = string.gsub(rawId, "\\", "")
        local numberMatch = string.match(mId, "%d+")
        local possibleItems
        for key, items in pairs(MeshMap) do
            if key == mId or string.match(key, "%d+") == numberMatch then possibleItems = items; break end
        end
        if possibleItems then
            if #possibleItems == 1 then detectedItem = possibleItems[1]; break
            else
                local objName = obj.Name:lower()
                local parentName = obj.Parent and obj.Parent.Name:lower() or ""
                for _, item in ipairs(possibleItems) do
                    local iName = item.name:lower()
                    if objName == iName or parentName == iName or string.find(parentName, iName, 1, true) then
                        detectedItem = item; break
                    end
                end
                if not detectedItem then detectedItem = possibleItems[1] end
                break
            end
        end
    end
    if not detectedItem then
        local n = obj.Name:lower(); if NameMap[n] then detectedItem = NameMap[n] end
    end
    if detectedItem then
        local posType, position = 0, nil
        if obj:IsA("BasePart") then posType, position = 1, obj.Position
        elseif obj:IsA("Model") then
            if obj.PrimaryPart then posType, position = 2, obj.PrimaryPart.Position
            else posType, position = 3, obj:GetPivot().Position end
        end
        if not position then return end
        for _, cacheData in pairs(CachedItems) do
            if cacheData.Data and cacheData.Data.name == detectedItem.name and cacheData.Position then
                if (cacheData.Position - position).Magnitude < 5 then return end
            end
        end
        local textLabel = Instance.new("TextLabel")
        textLabel.BackgroundTransparency = 1; textLabel.Font = Enum.Font.GothamBold
        textLabel.TextColor3 = Color3.new(1,1,1); textLabel.RichText = true
        textLabel.AnchorPoint = Vector2.new(0.5, 0.5); textLabel.AutomaticSize = Enum.AutomaticSize.XY
        textLabel.Visible = false; textLabel.Parent = espGui
        Instance.new("UIStroke", textLabel).Thickness = 1
        local gradient = Instance.new("UIGradient", textLabel); gradient.Rotation = 0
        local offArrow = Instance.new("TextLabel")
        offArrow.BackgroundTransparency = 1; offArrow.Font = Enum.Font.GothamBold
        offArrow.Text = "v"; offArrow.TextColor3 = Color3.new(1,1,1); offArrow.TextSize = 20
        offArrow.AnchorPoint = Vector2.new(0.5, 0.5); offArrow.Visible = false; offArrow.Parent = espGui
        Instance.new("UIStroke", offArrow).Thickness = 1
        local drawings = { Label = textLabel, Gradient = gradient, OffArrow = offArrow }
        local targetMesh = obj
        local mannequin
        if obj.Name == "Mannequin" then mannequin = obj
        elseif obj:FindFirstChild("Mannequin") then mannequin = obj:FindFirstChild("Mannequin")
        elseif obj.Parent and obj.Parent:FindFirstChild("Mannequin") then mannequin = obj.Parent:FindFirstChild("Mannequin")
        elseif obj.Parent and obj.Parent.Parent and obj.Parent.Parent:FindFirstChild("Mannequin") then
            mannequin = obj.Parent.Parent:FindFirstChild("Mannequin")
        end
        if mannequin then targetMesh = mannequin
        elseif obj:IsA("Model") then
            local found = false
            for _, child in ipairs(obj:GetDescendants()) do
                if child:IsA("MeshPart") or (child:IsA("Part") and child:FindFirstChildOfClass("SpecialMesh")) then
                    targetMesh = child; found = true; break
                end
            end
            if not found and obj.PrimaryPart then targetMesh = obj.PrimaryPart end
        end
        CachedItems[obj] = {
            Data = detectedItem, Drawings = drawings, TargetMesh = targetMesh,
            PosType = posType, Position = position, IsDropped = isInDropped, ShopZone = shopZone,
        }
    end
end

local function RemoveItemFromCache(obj)
    if CachedItems[obj] then
        if CachedItems[obj].Drawings.Label then pcall(function() CachedItems[obj].Drawings.Label:Destroy() end) end
        if CachedItems[obj].Drawings.OffArrow then pcall(function() CachedItems[obj].Drawings.OffArrow:Destroy() end) end
        CachedItems[obj] = nil
    end
end

local DBReady, ESPReady = false, false
task.spawn(function() FetchDatabases(); DBReady = true end)
task.spawn(function()
    while not DBReady do task.wait(0.1) end
    Workspace.DescendantAdded:Connect(function(obj) AddItemToCache(obj) end)
    Workspace.DescendantRemoving:Connect(RemoveItemFromCache)
    local objsToScan = {}
    for _, child in ipairs(Workspace:GetChildren()) do
        if child.Name == "DroppedItems" or string.find(child.Name, "Shop_ShopZone") == 1 then
            table.insert(objsToScan, child)
            for _, desc in ipairs(child:GetDescendants()) do table.insert(objsToScan, desc) end
        end
    end
    for i, obj in ipairs(objsToScan) do
        AddItemToCache(obj); if i % 50 == 0 then task.wait() end
    end
    ESPReady = true
end)

-- ========== TP HELPERS ==========
local function getHRP()
    local char = LocalPlayer.Character
    return char and char:FindFirstChild("HumanoidRootPart")
end
local function teleportTo(pos)
    local hrp = getHRP(); if not hrp then return end
    hrp.CFrame = CFrame.new(pos + Vector3.new(0, 3, 0))
end
local function findBestShop()
    local zoneTotals, zonePositions = {}, {}
    for _, data in pairs(CachedItems) do
        if not data.IsDropped and data.ShopZone and data.ShopZone.Parent then
            local zone = data.ShopZone
            local price = (data.Data and data.Data.fairPrice) or 0
            zoneTotals[zone] = (zoneTotals[zone] or 0) + price
            if not zonePositions[zone] then
                local ok, pivot = pcall(function() return zone:GetPivot().Position end)
                if ok then zonePositions[zone] = pivot end
            end
        end
    end
    local bestZone, bestTotal = nil, -1
    for zone, total in pairs(zoneTotals) do
        if total > bestTotal then bestTotal = total; bestZone = zone end
    end
    if bestZone and zonePositions[bestZone] then return zonePositions[bestZone] end
    return nil
end
local function tpToTarget(name)
    if name == "Baryga" then teleportTo(COORDS_BARYGA)
    elseif name == "Tsum" then teleportTo(COORDS_TSUM)
    elseif name == "Best Shop" then local p = findBestShop(); if p then teleportTo(p) end end
end
local pendingTpTarget = nil
local function resetAndTp(targetName)
    pendingTpTarget = targetName
    local char = LocalPlayer.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid")
    if hum then hum.Health = 0 else pcall(function() LocalPlayer:LoadCharacter() end) end
end

-- ========== PROXIMITY PROMPTS ==========
local PromptSet = {}
local function patchPrompt(p)
    pcall(function()
        p.HoldDuration = 0; p.MaxActivationDistance = math.huge; p.RequiresLineOfSight = false
    end)
end
local function indexPrompt(d)
    if d:IsA("ProximityPrompt") then PromptSet[d] = true; patchPrompt(d) end
end
for _, d in ipairs(Workspace:GetDescendants()) do indexPrompt(d) end
Workspace.DescendantAdded:Connect(indexPrompt)
Workspace.DescendantRemoving:Connect(function(d) if PromptSet[d] then PromptSet[d] = nil end end)
local function promptWorldPos(prompt)
    local p = prompt.Parent; if not p then return nil end
    if p:IsA("BasePart") then return p.Position end
    if p:IsA("Attachment") then return p.WorldPosition end
    local m = p:IsA("Model") and p or p:FindFirstAncestorOfClass("Model")
    if m then local ok, pivot = pcall(function() return m:GetPivot().Position end); if ok then return pivot end end
    return nil
end
local function fireOne(prompt)
    patchPrompt(prompt)
    if fireproximityprompt then pcall(fireproximityprompt, prompt)
    else pcall(function() prompt:InputHoldBegin(); prompt:InputHoldEnd() end) end
end

-- ========== AUTO PICKUP ==========
RunService.Heartbeat:Connect(function()
    if not Config.AutoPickup.Enabled then return end
    local hrp = getHRP(); if not hrp then return end
    for prompt in pairs(PromptSet) do
        if prompt.Parent and prompt.Enabled then
            local wp = promptWorldPos(prompt)
            if wp and (wp - hrp.Position).Magnitude <= Config.AutoPickup.Range then
                local objMatch = false
                for obj, data in pairs(CachedItems) do
                    if obj.Parent and (wp - data.Position).Magnitude < 8 then
                        if data.IsDropped and Config.AutoPickup.PickupDropped then objMatch = true; break end
                    end
                end
                if objMatch or Config.AutoPickup.PickupUnknown then fireOne(prompt) end
            end
        end
    end
end)

