local invisConn
local function startInvisLoop()
    if invisConn then return end
    invisConn = RunService.RenderStepped:Connect(function()
        if not (Config.Skin.Enabled and Config.Skin.HideSelf) then return end
        local char = LocalPlayer.Character; if not char then return end
        for _, d in ipairs(char:GetDescendants()) do
            if d:IsA("BasePart") and d.LocalTransparencyModifier ~= 1 then d.LocalTransparencyModifier = 1
            elseif d:IsA("Decal") and d.Transparency ~= 1 then d.Transparency = 1 end
        end
    end)
end
local function stopInvisLoop()
    if invisConn then invisConn:Disconnect(); invisConn = nil end
    local char = LocalPlayer.Character
    if char then
        for _, d in ipairs(char:GetDescendants()) do
            if d:IsA("BasePart") then d.LocalTransparencyModifier = 0
            elseif d:IsA("Decal") then d.Transparency = 0 end
        end
    end
end

local Skin = { Model = nil, SpinAccum = 0 }
local function prepModel(objs)
    local root = objs[1]
    local model
    if root:IsA("Model") then model = root
    elseif root:IsA("BasePart") then
        model = Instance.new("Model"); root.Parent = model; model.PrimaryPart = root
    else
        model = Instance.new("Model")
        for _, c in ipairs(root:GetChildren()) do c.Parent = model end
    end
    if not (model.PrimaryPart and model.PrimaryPart.Parent) then
        local pp = model:FindFirstChildWhichIsA("BasePart", true); if pp then model.PrimaryPart = pp end
    end
    for _, d in ipairs(model:GetDescendants()) do
        if d:IsA("BasePart") then
            d.Anchored = true; d.CanCollide = false; d.CanQuery = false
            d.CanTouch = false; d.Massless = true; d.Locked = true
        end
    end
    return model
end
local function unloadSkin()
    if Skin.Model then pcall(function() Skin.Model:Destroy() end); Skin.Model = nil end
end
local function loadSkin(assetId)
    unloadSkin()
    local ok, objs = pcall(function() return game:GetObjects("rbxassetid://" .. tostring(assetId)) end)
    if not ok or not objs or #objs == 0 then warn("[Skin] fail:", assetId); return end
    local m = prepModel(objs); pcall(function() m:ScaleTo(Config.Skin.Scale) end)
    m.Name = "__TTH_Skin"; m.Parent = Workspace; Skin.Model = m
end

RunService.Heartbeat:Connect(function(dt)
    if not Config.Skin.Enabled then if Skin.Model then unloadSkin() end return end
    if not Skin.Model or not Skin.Model.Parent then
        if Config.Skin.AssetId and Config.Skin.AssetId ~= 0 then loadSkin(Config.Skin.AssetId) end
        return
    end
    local char = LocalPlayer.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart"); if not hrp then return end
    Skin.SpinAccum = Skin.SpinAccum + Config.Skin.SpinSpeed * dt
    local _, charYaw, _ = hrp.CFrame:ToOrientation()
    local yawBase = Config.Skin.FollowRotation and charYaw or 0
    local cf = CFrame.new(hrp.Position)
        * CFrame.Angles(0, yawBase + math.rad(Config.Skin.RotationY + Skin.SpinAccum), 0)
        * CFrame.new(0, Config.Skin.OffsetY, Config.Skin.OffsetZ)
    pcall(function() Skin.Model:PivotTo(cf) end)
end)

local Comp = { Model = nil, Angle = 0, Bob = 0, LastCF = nil }
local function unloadComp()
    if Comp.Model then pcall(function() Comp.Model:Destroy() end); Comp.Model = nil end
    Comp.LastCF = nil
end
local function loadComp(assetId)
    unloadComp()
    local ok, objs = pcall(function() return game:GetObjects("rbxassetid://" .. tostring(assetId)) end)
    if not ok or not objs or #objs == 0 then warn("[Comp] fail:", assetId); return end
    local m = prepModel(objs); pcall(function() m:ScaleTo(Config.Companion.Scale) end)
    m.Name = "__TTH_Companion"; m.Parent = Workspace; Comp.Model = m
end

RunService.Heartbeat:Connect(function(dt)
    if not Config.Companion.Enabled then if Comp.Model then unloadComp() end return end
    if not Comp.Model or not Comp.Model.Parent then
        if Config.Companion.AssetId and Config.Companion.AssetId ~= 0 then loadComp(Config.Companion.AssetId) end
        return
    end
    local char = LocalPlayer.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart"); if not hrp then return end
    Comp.Bob = Comp.Bob + dt * 3
    local bobOffset = Config.Companion.Bobbing and (math.sin(Comp.Bob) * 0.4) or 0
    local targetCF
    if Config.Companion.Mode == "Orbit" then
        Comp.Angle = (Comp.Angle + Config.Companion.OrbitSpeed * dt) % 360
        local rad = math.rad(Comp.Angle); local r = Config.Companion.OrbitRadius
        local offset = Vector3.new(math.cos(rad) * r, Config.Companion.OrbitHeight + bobOffset, math.sin(rad) * r)
        local pos = hrp.Position + offset
        local lookCF = CFrame.new(pos, pos + Vector3.new(-math.cos(rad), 0, -math.sin(rad)))
        local spinYaw = math.rad((tick() * Config.Companion.SpinSpeed) % 360)
        targetCF = lookCF * CFrame.Angles(0, spinYaw, 0)
    else
        local back = -hrp.CFrame.LookVector
        local targetPos = hrp.Position + back * Config.Companion.FollowDistance
            + Vector3.new(0, Config.Companion.FollowHeight + bobOffset, 0)
        local currentPos = Comp.LastCF and Comp.LastCF.Position or targetPos
        local alpha = math.clamp(dt * Config.Companion.FollowSmooth, 0, 1)
        local newPos = currentPos:Lerp(targetPos, alpha)
        local spinYaw = math.rad((tick() * Config.Companion.SpinSpeed) % 360)
        if Config.Companion.FaceYou then
            local lookCF = CFrame.new(newPos, Vector3.new(hrp.Position.X, newPos.Y, hrp.Position.Z))
            targetCF = lookCF * CFrame.Angles(0, spinYaw, 0)
        else
            local _, yaw, _ = hrp.CFrame:ToOrientation()
            targetCF = CFrame.new(newPos) * CFrame.Angles(0, yaw + spinYaw, 0)
        end
    end
    Comp.LastCF = targetCF
    pcall(function() Comp.Model:PivotTo(targetCF) end)
end)

local origGfx = {
    GlobalShadows = Lighting.GlobalShadows, FogEnd = Lighting.FogEnd,
    FogStart = Lighting.FogStart, EnvDiff = Lighting.EnvironmentDiffuseScale,
    EnvSpec = Lighting.EnvironmentSpecularScale,
}
local potatoApplied = false
local function applyPotato(on)
    pcall(function()
        if on then
            settings().Rendering.QualityLevel = Enum.QualityLevel.Level01
            Lighting.GlobalShadows = false; Lighting.FogEnd = 100000; Lighting.FogStart = 100000
            Lighting.EnvironmentDiffuseScale = 0; Lighting.EnvironmentSpecularScale = 0
            for _, d in ipairs(Workspace:GetDescendants()) do
                if d:IsA("BasePart") and (not Skin.Model or not d:IsDescendantOf(Skin.Model))
                    and (not Comp.Model or not d:IsDescendantOf(Comp.Model)) then
                    d.Material = Enum.Material.Plastic; d.Reflectance = 0
                elseif d:IsA("ParticleEmitter") or d:IsA("Trail") or d:IsA("Smoke")
                    or d:IsA("Fire") or d:IsA("Sparkles") then d.Enabled = false end
            end
            for _, d in ipairs(Lighting:GetDescendants()) do
                if d:IsA("BlurEffect") or d:IsA("BloomEffect") or d:IsA("SunRaysEffect")
                    or d:IsA("DepthOfFieldEffect") or d:IsA("ColorCorrectionEffect") then d.Enabled = false end
            end
            local terrain = Workspace:FindFirstChildOfClass("Terrain")
            if terrain then
                terrain.WaterWaveSize = 0; terrain.WaterWaveSpeed = 0
                terrain.WaterReflectance = 0; terrain.WaterTransparency = 1; terrain.Decoration = false
            end
            potatoApplied = true
        elseif potatoApplied then
            settings().Rendering.QualityLevel = Enum.QualityLevel.Automatic
            Lighting.GlobalShadows = origGfx.GlobalShadows
            Lighting.FogEnd = origGfx.FogEnd; Lighting.FogStart = origGfx.FogStart
            Lighting.EnvironmentDiffuseScale = origGfx.EnvDiff
            Lighting.EnvironmentSpecularScale = origGfx.EnvSpec
            potatoApplied = false
        end
    end)
end

