-- ========== ESP RENDER ==========
local function GetOffscreenPosition(pos)
    local vs = Camera.ViewportSize; local center = vs / 2
    local offset = Vector2.new(pos.X, pos.Y) - center
    if pos.Z < 0 then offset = -offset end
    local angle = math.atan2(offset.Y, offset.X)
    local rx, ry = math.cos(angle), math.sin(angle)
    local padding = 40
    local bX = center.X - padding; local bY = center.Y - padding
    local scale = math.min(bX / math.abs(rx), bY / math.abs(ry))
    return Vector2.new(center.X + rx * scale, center.Y + ry * scale), angle
end

RunService.RenderStepped:Connect(function()
    if not ESPReady then return end
    local activeH = 0
    for _, hl in ipairs(HighlightPool) do hl.Enabled = false end
    for obj, cacheData in pairs(CachedItems) do
        local itemData = cacheData.Data
        local rarityState = Config.Rarities[itemData.rarity or "Common"]
        if cacheData.Drawings.Label then cacheData.Drawings.Label.Visible = false end
        if cacheData.Drawings.OffArrow then cacheData.Drawings.OffArrow.Visible = false end
        local isDropped = cacheData.IsDropped
        if not obj.Parent then continue end
        if isDropped then
            if not Config.ESP.ScanDropped then continue end
        else
            if not Config.ESP.Enabled or not rarityState or not rarityState.Enabled then continue end
            if Config.Sort.Enabled then
                if Config.Sort.Modes["Chance"] then
                    if not itemData.spawnChance or itemData.spawnChance > Config.Sort.MaxChance then continue end
                end
                if Config.Sort.Modes["Price"] then
                    local price = itemData.fairPrice or 0
                    if price < Config.Sort.MinPrice or price > Config.Sort.MaxPrice then continue end
                end
            end
        end
        local activeColor = isDropped and Config.ESP.ScanDroppedColor or rarityState.Color
        local position
        if cacheData.PosType == 1 then position = obj.Position
        elseif cacheData.PosType == 2 then position = obj.PrimaryPart.Position
        elseif cacheData.PosType == 3 then position = obj:GetPivot().Position
        else continue end
        local pos, onScreen = Camera:WorldToViewportPoint(position)
        if onScreen then
            local yOff = 0
            if cacheData.TargetMesh then
                pcall(function()
                    if cacheData.TargetMesh:IsA("Model") then yOff = cacheData.TargetMesh:GetExtentsSize().Y / 2
                    elseif cacheData.TargetMesh:IsA("BasePart") then yOff = cacheData.TargetMesh.Size.Y / 2 end
                end)
            end
            local topPos = Camera:WorldToViewportPoint(position + Vector3.new(0, yOff + 0.5, 0))
            local baseZ = math.floor(10000 - pos.Z)
            local parts = {}
            if Config.ESP.ShowName then
                local nt = isDropped and ("DROP " .. itemData.name) or itemData.name
                table.insert(parts, string.format('<font size="%d"><b>%s</b></font>', Config.ESP.NameSize, nt))
            end
            if Config.ESP.ShowPrice and itemData.fairPrice then
                table.insert(parts, string.format('<font size="%d">%s</font>', Config.ESP.PriceSize, tostring(itemData.fairPrice)))
            end
            if Config.ESP.ShowEco and itemData.economyProfile then
                table.insert(parts, string.format('<font size="%d">%s</font>', Config.ESP.EcoSize, itemData.economyProfile))
            end
            local fullText = table.concat(parts, " ")
            local hrpChar = LocalPlayer.Character and LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
            local meters = hrpChar and math.floor((hrpChar.Position - position).Magnitude * 0.28) or 0
            if Config.ESP.RenderDistEnabled and meters > Config.ESP.RenderDist then
                cacheData.Drawings.Label.Visible = false
            else
                if Config.ESP.ShowDistance and hrpChar then
                    fullText = fullText .. string.format('\n<font size="%d" color="#FFFFFF">[%dm]</font>', Config.ESP.DistanceSize, meters)
                end
                if Config.ESP.ShowSpawn and itemData.spawnChance then
                    fullText = fullText .. string.format('\n<font size="%d" color="#FFFFFF">chance - %s%%</font>', Config.ESP.SpawnSize, tostring(itemData.spawnChance))
                end
                cacheData.Drawings.Label.Text = fullText
                cacheData.Drawings.Label.Position = UDim2.new(0, topPos.X, 0, topPos.Y)
                cacheData.Drawings.Label.AnchorPoint = Vector2.new(0.5, 1)
                cacheData.Drawings.Label.ZIndex = baseZ
                local g = (tick() % 2) / 2
                cacheData.Drawings.Gradient.Color = ColorSequence.new({
                    ColorSequenceKeypoint.new(0, activeColor),
                    ColorSequenceKeypoint.new(0.5, Color3.new(1, 1, 1)),
                    ColorSequenceKeypoint.new(1, activeColor),
                })
                cacheData.Drawings.Gradient.Offset = Vector2.new(-1 + g * 2, 0)
                cacheData.Drawings.Label.Visible = true
                if Config.ESP.ChamsEnabled and activeH < 31 then
                    activeH = activeH + 1
                    local hl = HighlightPool[activeH]
                    hl.Adornee = cacheData.TargetMesh
                    hl.FillColor = Config.ESP.ChamsColor; hl.OutlineColor = Color3.new(1, 1, 1)
                    hl.FillTransparency = Config.ESP.ChamsTransparency; hl.OutlineTransparency = 0.2
                    hl.Enabled = true
                end
            end
        else
            if Config.ESP.OffscreenEnabled then
                local hrpChar = LocalPlayer.Character and LocalPlayer.Character:FindFirstChild("HumanoidRootPart")
                local meters = hrpChar and math.floor((hrpChar.Position - position).Magnitude * 0.28) or 0
                if not (Config.ESP.RenderDistEnabled and meters > Config.ESP.RenderDist) then
                    local edgePos, angle = GetOffscreenPosition(pos)
                    local nt = isDropped and ("DROP " .. itemData.name) or itemData.name
                    local text = string.format("<b>%s</b> <font size='10'>(%s)</font>", nt, itemData.rarity or "Normal")
                    cacheData.Drawings.Label.Text = text
                    local od = 20
                    local tp = edgePos - Vector2.new(math.cos(angle) * od, math.sin(angle) * od)
                    cacheData.Drawings.Label.Position = UDim2.new(0, tp.X, 0, tp.Y)
                    local ax = (tp.X > Camera.ViewportSize.X / 2) and 1 or 0
                    local ay = (tp.Y > Camera.ViewportSize.Y / 2) and 1 or 0
                    cacheData.Drawings.Label.AnchorPoint = Vector2.new(ax, ay)
                    cacheData.Drawings.Label.ZIndex = math.floor(10000 - math.abs(pos.Z))
                    local g = (tick() % 2) / 2
                    cacheData.Drawings.Gradient.Color = ColorSequence.new({
                        ColorSequenceKeypoint.new(0, activeColor),
                        ColorSequenceKeypoint.new(0.5, Color3.new(1, 1, 1)),
                        ColorSequenceKeypoint.new(1, activeColor),
                    })
                    cacheData.Drawings.Gradient.Offset = Vector2.new(-1 + g * 2, 0)
                    cacheData.Drawings.Label.Visible = true
                    if cacheData.Drawings.OffArrow then
                        cacheData.Drawings.OffArrow.Position = UDim2.new(0, edgePos.X, 0, edgePos.Y)
                        cacheData.Drawings.OffArrow.Rotation = math.deg(angle) - 90
                        cacheData.Drawings.OffArrow.Visible = true
                    end
                end
            end
        end
    end
end)

-- ========== SPEED ==========
local lastSpeedEnabled = false
RunService.Heartbeat:Connect(function()
    local char = LocalPlayer.Character
    local hum = char and char:FindFirstChildOfClass("Humanoid"); if not hum then return end
    if Config.Movement.SpeedEnabled then
        if hum.WalkSpeed ~= Config.Movement.Speed then hum.WalkSpeed = Config.Movement.Speed end
        lastSpeedEnabled = true
    elseif lastSpeedEnabled then hum.WalkSpeed = 16; lastSpeedEnabled = false end
end)

-- ========== FLY + INF JUMP ==========
local Fly = { BV = nil, BG = nil, JumpBoost = 0, MobileUp = false, MobileDown = false }
local function flyDetach()
    if Fly.BV then Fly.BV:Destroy() Fly.BV = nil end
    if Fly.BG then Fly.BG:Destroy() Fly.BG = nil end
end
local function flyAttach()
    local c = LocalPlayer.Character; if not c then return end
    local hrp = c:FindFirstChild("HumanoidRootPart"); if not hrp then return end
    flyDetach()
    Fly.BV = Instance.new("BodyVelocity"); Fly.BV.Name = "__TTH_FlyVel"
    Fly.BV.MaxForce = Vector3.new(9e9, 9e9, 9e9); Fly.BV.Velocity = Vector3.new()
    Fly.BV.Parent = hrp
    Fly.BG = Instance.new("BodyGyro"); Fly.BG.Name = "__TTH_FlyGyro"
    Fly.BG.MaxTorque = Vector3.new(9e9, 9e9, 9e9); Fly.BG.P = 9e4
    Fly.BG.CFrame = Camera.CFrame; Fly.BG.Parent = hrp
    Fly.JumpBoost = 0
end

RunService.Heartbeat:Connect(function(dt)
    if not Config.Movement.FlyEnabled then if Fly.BV then flyDetach() end return end
    local c = LocalPlayer.Character
    local hum = c and c:FindFirstChildOfClass("Humanoid")
    local hrp = c and c:FindFirstChild("HumanoidRootPart")
    if not hum or not hrp then return end
    if not Fly.BV or Fly.BV.Parent ~= hrp then flyAttach() end
    local camCF = Camera.CFrame
    local md = hum.MoveDirection
    local localD = camCF:VectorToObjectSpace(md)
    local dir = camCF.LookVector * (-localD.Z) + camCF.RightVector * localD.X
    local vert = 0
    if UIS:IsKeyDown(Enum.KeyCode.Space) or Fly.MobileUp then vert = 1
    elseif UIS:IsKeyDown(Enum.KeyCode.LeftShift) or UIS:IsKeyDown(Enum.KeyCode.LeftControl) or Fly.MobileDown then vert = -1 end
    if Fly.JumpBoost > 0 then vert = vert + Fly.JumpBoost; Fly.JumpBoost = math.max(0, Fly.JumpBoost - dt * 4) end
    dir = dir + Vector3.new(0, vert, 0)
    dir = (dir.Magnitude > 0) and dir.Unit * Config.Movement.FlySpeed or Vector3.new()
    Fly.BV.Velocity = dir
    Fly.BG.CFrame = camCF
end)

UIS.JumpRequest:Connect(function()
    if Config.Movement.InfJumpEnabled then
        local c = LocalPlayer.Character; local hum = c and c:FindFirstChildOfClass("Humanoid")
        if hum then hum:ChangeState(Enum.HumanoidStateType.Jumping) end
    end
    if Config.Movement.FlyEnabled then Fly.JumpBoost = 1.5 end
end)

-- ========== CHARACTER ADDED ==========
LocalPlayer.CharacterAdded:Connect(function(char)
    task.wait(1)
    if pendingTpTarget then
        char:WaitForChild("HumanoidRootPart", 10)
        task.wait(0.3)
        tpToTarget(pendingTpTarget)
        pendingTpTarget = nil
    end
    if Config.Skin.Enabled and Config.Skin.HideSelf then startInvisLoop() end
    if Config.Movement.FlyEnabled then flyAttach() end
end)

Window.onUnloaded:Connect(function()
    if espGui then espGui:Destroy() end
    if hlFolder then hlFolder:Destroy() end
    unloadSkin(); stopInvisLoop(); unloadComp()
    flyDetach()
    if Config.Gfx.Potato then applyPotato(false) end
    local fab = CoreGui:FindFirstChild("__TTH_FAB"); if fab then fab:Destroy() end
end)

-- ===================================================================
-- =====   MOBILE FAB (toggle menu + fly up/down)                =====
-- ===================================================================
if IsMobile then
    task.spawn(function()
        task.wait(2)
        local maclibGui
        for _ = 1, 30 do
            for _, g in ipairs(CoreGui:GetChildren()) do
                if g:IsA("ScreenGui")
                    and g.Name ~= "TTH_ESP"
                    and g.Name ~= "__TTH_LoadBanner"
                    and g.Name ~= "TTH_Highlights"
                    and g.Name ~= "__TTH_FAB"
                    and #g:GetChildren() > 0 then
                    maclibGui = g
                end
            end
            if maclibGui then break end
            task.wait(0.3)
        end

        local fabGui = CoreGui:FindFirstChild("__TTH_FAB")
        if fabGui then fabGui:Destroy() end
        fabGui = Instance.new("ScreenGui")
        fabGui.Name = "__TTH_FAB"
        fabGui.IgnoreGuiInset = true
        fabGui.ResetOnSpawn = false
        fabGui.DisplayOrder = 9998
        fabGui.Parent = CoreGui

        local btn = Instance.new("TextButton", fabGui)
        btn.AnchorPoint = Vector2.new(0, 0)
        btn.Position = UDim2.new(0, 12, 0, 90)
        btn.Size = UDim2.fromOffset(56, 56)
        btn.BackgroundColor3 = Color3.fromRGB(18, 16, 30)
        btn.BackgroundTransparency = 0.1
        btn.AutoButtonColor = false
        btn.BorderSizePixel = 0
        btn.Text = "TT"
        btn.Font = Enum.Font.GothamBold
        btn.TextSize = 18
        btn.TextColor3 = Color3.fromRGB(220, 200, 255)
        btn.Active = true
        btn.Draggable = true
        Instance.new("UICorner", btn).CornerRadius = UDim.new(1, 0)
        local stroke = Instance.new("UIStroke", btn)
        stroke.Color = Color3.fromRGB(138, 43, 226)
        stroke.Thickness = 2

        local dot = Instance.new("Frame", btn)
        dot.AnchorPoint = Vector2.new(1, 0)
        dot.Position = UDim2.new(1, -4, 0, 4)
        dot.Size = UDim2.fromOffset(10, 10)
        dot.BackgroundColor3 = Color3.fromRGB(0, 255, 100)
        dot.BorderSizePixel = 0
        Instance.new("UICorner", dot).CornerRadius = UDim.new(1, 0)

        local menuOpen = true
        local function setMenu(open)
            menuOpen = open
            dot.BackgroundColor3 = open and Color3.fromRGB(0, 255, 100) or Color3.fromRGB(255, 80, 80)
            local ok = false
            for _, name in ipairs({"Toggle","SetVisible","SetOpen","SetEnabled"}) do
                if not ok and type(Window[name]) == "function" then
                    pcall(function()
                        if name == "Toggle" then Window:Toggle()
                        else Window[name](Window, open) end
                    end)
                    ok = true
                end
            end
            if maclibGui and maclibGui:IsA("ScreenGui") then
                pcall(function() maclibGui.Enabled = open end)
            end
        end

        local pressStart, pressPos
        btn.InputBegan:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.Touch
            or input.UserInputType == Enum.UserInputType.MouseButton1 then
                pressStart = tick()
                pressPos = input.Position
            end
        end)
        btn.InputEnded:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.Touch
            or input.UserInputType == Enum.UserInputType.MouseButton1 then
                if pressStart and (tick() - pressStart) < 0.35 then
                    local moved = pressPos and (input.Position - pressPos).Magnitude or 0
                    if moved < 10 then setMenu(not menuOpen) end
                end
                pressStart = nil
            end
        end)

        -- Fly Up/Down pad
        local function mkPadBtn(text, posY, color)
            local b = Instance.new("TextButton", fabGui)
            b.AnchorPoint = Vector2.new(1, 1)
            b.Position = UDim2.new(1, -20, 1, posY)
            b.Size = UDim2.fromOffset(64, 64)
            b.BackgroundColor3 = Color3.fromRGB(20, 18, 35)
            b.BackgroundTransparency = 0.1
            b.Text = text
            b.Font = Enum.Font.GothamBold
            b.TextSize = 30
            b.TextColor3 = Color3.fromRGB(255, 255, 255)
            b.AutoButtonColor = false
            b.BorderSizePixel = 0
            Instance.new("UICorner", b).CornerRadius = UDim.new(1, 0)
            local s = Instance.new("UIStroke", b)
            s.Color = color; s.Thickness = 2
            return b
        end
        local bU = mkPadBtn("↑", -190, Color3.fromRGB(138, 43, 226))
        local bD = mkPadBtn("↓", -110, Color3.fromRGB(0, 191, 255))
        local function bind(b, flag)
            b.InputBegan:Connect(function(i)
                if i.UserInputType == Enum.UserInputType.Touch
                or i.UserInputType == Enum.UserInputType.MouseButton1 then Fly[flag] = true end
            end)
            b.InputEnded:Connect(function(i)
                if i.UserInputType == Enum.UserInputType.Touch
                or i.UserInputType == Enum.UserInputType.MouseButton1 then Fly[flag] = false end
            end)
        end
        bind(bU, "MobileUp")
        bind(bD, "MobileDown")

        print(" mobile FAB ready")
    end)
end

print(string.format(" loaded | %s | %dx%d",
    IsMobile and "mobile" or "pc", WIN_SIZE.X.Offset, WIN_SIZE.Y.Offset))

